const fs = require("fs");

// Usage:
//   node scripts/format_snarkjs_calldata.js proof/valid_calldata_raw.txt proof/valid_calldata.json
//
// Robust formatter for snarkjs soliditycalldata output.
// It handles:
//   1) UTF-8 raw output generated by cmd /c redirection;
//   2) UTF-16LE raw output generated by Windows PowerShell redirection;
//   3) accidental terminal color/noise bytes around the calldata;
//   4) raw calldata either as: [a],[b],[c],[input] or [[a],[b],[c],[input]].

const input = process.argv[2];
const output = process.argv[3];

if (!input || !output) {
  console.error("Usage: node scripts/format_snarkjs_calldata.js <raw_calldata.txt> <output.json>");
  process.exit(1);
}

function decodeText(filePath) {
  const buf = fs.readFileSync(filePath);

  // UTF-16LE BOM: FF FE. PowerShell 5 redirection commonly writes UTF-16LE.
  if (buf.length >= 2 && buf[0] === 0xff && buf[1] === 0xfe) {
    return buf.slice(2).toString("utf16le");
  }

  // Heuristic: many NUL bytes means UTF-16LE without BOM.
  let nulCount = 0;
  const checkLen = Math.min(buf.length, 200);
  for (let i = 0; i < checkLen; i++) {
    if (buf[i] === 0) nulCount++;
  }
  if (nulCount > checkLen * 0.20) {
    return buf.toString("utf16le");
  }

  return buf.toString("utf8");
}

function stripAnsi(s) {
  return s.replace(/\x1B\[[0-?]*[ -/]*[@-~]/g, "");
}

function extractCalldataText(s) {
  let text = stripAnsi(s)
    .replace(/^\uFEFF/, "")
    .replace(/\0/g, "")
    .trim();

  // Keep only the bracketed calldata region. Some terminals can prepend noise.
  const first = text.indexOf("[");
  const last = text.lastIndexOf("]");
  if (first < 0 || last < first) {
    throw new Error("Could not find bracketed snarkjs calldata in raw file.");
  }
  text = text.slice(first, last + 1).trim();

  // Remove non-printable replacement chars occasionally produced by bad decoding.
  text = text.replace(/\uFFFD/g, "").trim();
  return text;
}

function parseRawCalldata(rawText) {
  const text = extractCalldataText(rawText);

  let parsed;
  try {
    // snarkjs usually outputs: [a],[b],[c],[input]
    parsed = JSON.parse(`[${text}]`);
  } catch (e1) {
    try {
      // Some wrappers may already output: [[a],[b],[c],[input]]
      parsed = JSON.parse(text);
    } catch (e2) {
      console.error("Failed to parse snarkjs calldata. First 300 chars after cleanup:");
      console.error(text.slice(0, 300));
      throw e1;
    }
  }

  // If parsed is [[[...]],[[...]],...] because the raw text was already wrapped, unwrap once.
  if (Array.isArray(parsed) && parsed.length === 1 && Array.isArray(parsed[0]) && parsed[0].length === 4) {
    parsed = parsed[0];
  }

  if (!Array.isArray(parsed) || parsed.length !== 4) {
    throw new Error(`Expected 4 calldata arguments [pA,pB,pC,pubSignals], got ${Array.isArray(parsed) ? parsed.length : typeof parsed}`);
  }

  return {
    pA: parsed[0],
    pB: parsed[1],
    pC: parsed[2],
    pubSignals: parsed[3]
  };
}

const raw = decodeText(input);
const obj = parseRawCalldata(raw);
fs.writeFileSync(output, JSON.stringify(obj, null, 2), "utf8");
console.log(`Wrote ${output}`);
